import sys
class Solution:
    def sort(self, nums: list[int]) -> None:
        n = len(nums)
        for i in range(n - 1):
            swapped = False
            for j in range(n - i - 1):
                if nums[j] > nums[j + 1]:
                    nums[j], nums[j + 1] = nums[j + 1], nums[j]
                    swapped = True
            if not swapped:
                break
        # print the sorted array
        print(*nums)

if __name__ == '__main__':
    T = int(sys.stdin.readline().strip())
