#include <iostream>
using namespace std;
class Solution {
public:
    void sort(int* nums, int n) {
        for (int i = 0; i < n - 1; i++) {
            bool swapped = false;
            for (int j = 0; j < n - i - 1; j++) {
                if (nums[j] > nums[j + 1]) {
                    swap(nums[j], nums[j + 1]);
                    swapped = true;
                }
            }
            if (!swapped) break;
        }
        // print the sorted array
        for (int i = 0; i < n; i++) cout << nums[i] << ' ';
        cout << endl;
    }
};
int main() {
    int T;
    cin >> T;
    for (int i = 0; i < T; i++) {
        int n;
        cin >> n;
        int* nums = new int[n];
        for (int j = 0; j < n; j++) cin >> nums[j];
        Solution obj;
        obj.sort(nums, n);
        delete[] nums;
    }
    return 0;
}
